<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #121212;
            --text-color: #e0e0e0;
            --accent-color: #bb86fc;
            --button-bg: #333;
            --button-hover: #444;
            --canvas-border: #555;
        }

        body {
            margin: 0;
            padding: 20px;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            min-height: 100vh;
        }

        h1 {
            margin-bottom: 20px;
            font-weight: 300;
            letter-spacing: 1px;
        }

        .controls-container {
            display: flex;
            gap: 10px;
            margin-bottom: 20px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            background-color: var(--button-bg);
            color: var(--text-color);
            border: none;
            padding: 10px 20px;
            font-size: 14px;
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.2s ease;
            box-shadow: 0 2px 5px rgba(0,0,0,0.3);
            min-width: 80px;
        }

        button:hover {
            background-color: var(--button-hover);
            transform: translateY(-1px);
        }

        button.active {
            background-color: var(--accent-color);
            color: #000;
            font-weight: bold;
        }

        #clear {
            background-color: #d32f2f;
        }

        #clear:hover {
            background-color: #b71c1c;
        }

        .canvas-container {
            position: relative;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
            border: 2px solid var(--canvas-border);
            border-radius: 4px;
            overflow: hidden;
        }

        canvas {
            display: block;
            cursor: crosshair;
        }

        .instructions {
            margin-top: 15px;
            font-size: 0.9em;
            color: #aaa;
            text-align: center;
            max-width: 600px;
        }
    </style>
</head>
<body>
    <h1>Falling Sand Sandbox</h1>

    <div class="controls-container">
        <button id="mat-sand" class="active">Sand</button>
        <button id="mat-water">Water</button>
        <button id="mat-wall">Wall</button>
        <button id="mat-acid">Acid</button>
        <button id="mat-empty">Eraser</button>
    </div>

    <div class="controls-container">
        <button id="clear">Clear Canvas</button>
    </div>

    <div class="canvas-container">
        <canvas id="sand" width="400" height="400"></canvas>
    </div>

    <p class="instructions">
        Click and drag to paint materials. 
        Sand falls, Water flows, Acid dissolves walls and sand.
    </p>

    <script>
        // Configuration
        const GRID_WIDTH = 100;
        const GRID_HEIGHT = 100;
        const CELL_SIZE = 4; // Each cell is 4x4 pixels

        // Material constants
        const EMPTY = 'empty';
        const SAND = 'sand';
        const WATER = 'water';
        const WALL = 'wall';
        const ACID = 'acid';

        class FallingSandSimulation {
            constructor(width, height) {
                this.w = width;
                this.h = height;
                this.grid = new Array(height).fill(null).map(() => new Array(width).fill(EMPTY));

                // Canvas setup
                this.canvas = document.getElementById('sand');
                this.ctx = this.canvas.getContext('2d');
                this.canvas.width = width * CELL_SIZE;
                this.canvas.height = height * CELL_SIZE;

                // Mouse interaction state
                this.isDrawing = false;
                this.currentMaterial = SAND;

                // Bind events
                this.bindEvents();
            }

            bindEvents() {
                const canvasRect = this.canvas.getBoundingClientRect();

                const getGridPos = (e) => {
                    const rect = this.canvas.getBoundingClientRect();
                    const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
                    const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);
                    return { x, y };
                };

                // Mouse events for drawing
                this.canvas.addEventListener('mousedown', (e) => {
                    this.isDrawing = true;
                    const pos = getGridPos(e);
                    if (pos.x >= 0 && pos.x < this.w && pos.y >= 0 && pos.y < this.h) {
                        this.set(pos.x, pos.y, this.currentMaterial);
                    }
                });

                this.canvas.addEventListener('mousemove', (e) => {
                    if (!this.isDrawing) return;

                    const pos = getGridPos(e);
                    // Add some noise to make painting smoother
                    if (pos.x >= 0 && pos.x < this.w && pos.y >= 0 && pos.y < this.h) {
                        this.set(pos.x, pos.y, this.currentMaterial);

                        // Optional: paint a small brush area
                        const brushSize = 1;
                        for (let dy = -brushSize; dy <= brushSize; dy++) {
                            for (let dx = -brushSize; dx <= brushSize; dx++) {
                                if (Math.random() > 0.5) continue; // Randomize slightly for natural look
                                const nx = pos.x + dx;
                                const ny = pos.y + dy;
                                if (nx >= 0 && nx < this.w && ny >= 0 && ny < this.h) {
                                    this.set(nx, ny, this.currentMaterial);
                                }
                            }
                        }
                    }
                });

                window.addEventListener('mouseup', () => {
                    this.isDrawing = false;
                });
            }

            get(x, y) {
                if (x < 0 || x >= this.w || y < 0 || y >= this.h) return EMPTY;
                return this.grid[y][x];
            }

            set(x, y, material) {
                if (x < 0 || x >= this.w || y < 0 || y >= this.h) return;
                this.grid[y][x] = material;
            }

            clear() {
                for (let y = 0; y < this.h; y++) {
                    for (let x = 0; x < this.w; x++) {
                        this.grid[y][x] = EMPTY;
                    }
                }
                this.render();
            }

            tick(n = 1) {
                // Process bottom-up to ensure particles move at most one cell per step
                for (let step = 0; step < n; step++) {
                    // Create a copy of the grid state for this tick to avoid double movement
                    const currentGrid = this.grid.map(row => [...row]);

                    // Process from bottom to top
                    for (let y = this.h - 1; y >= 0; y--) {
                        // Randomize x-direction for more natural behavior
                        const leftToRight = Math.random() > 0.5;
                        const xStart = leftToRight ? 0 : this.w - 1;
                        const xEnd = leftToRight ? this.w : -1;
                        const xStep = leftToRight ? 1 : -1;

                        for (let x = xStart; x !== xEnd; x += xStep) {
                            const material = currentGrid[y][x];

                            if (material === SAND) {
                                this.updateSand(x, y, currentGrid);
                            } else if (material === WATER) {
                                this.updateWater(x, y, currentGrid);
                            } else if (material === ACID) {
                                this.updateAcid(x, y, currentGrid);
                            }
                        }
                    }

                    // Update the main grid for next iteration
                    for (let y = 0; y < this.h; y++) {
                        for (let x = 0; x < this.w; x++) {
                            this.grid[y][x] = currentGrid[y][x];
                        }
                    }
                }

                // Render after simulation step
                this.render();
            }

            updateSand(x, y, grid) {
                if (y >= this.h - 1) return; // Bottom boundary

                const below = grid[y + 1][x];
                const belowLeft = x > 0 ? grid[y + 1][x - 1] : WALL;
                const belowRight = x < this.w - 1 ? grid[y + 1][x + 1] : WALL;

                // Try to fall straight down
                if (below === EMPTY) {
                    grid[y + 1][x] = SAND;
                    grid[y][x] = EMPTY;
                } else if (below === WATER || below === ACID) {
                    // Sand sinks in water/acid
                    grid[y + 1][x] = SAND;
                    grid[y][x] = below; // Swap with the liquid
                    grid[y + 1][x] = SAND; // Ensure sand is at bottom
                } else if (below === WALL) {
                    // Blocked by wall, try diagonal
                    const dir = Math.random() > 0.5 ? -1 : 1;
                    const side1 = x + dir >= 0 && x + dir < this.w ? grid[y + 1][x + dir] : WALL;

                    if (side1 === EMPTY) {
                        grid[y + 1][x + dir] = SAND;
                        grid[y][x] = EMPTY;
                    } else {
                        const side2 = x - dir >= 0 && x - dir < this.w ? grid[y + 1][x - dir] : WALL;
                        if (side2 === EMPTY) {
                            grid[y + 1][x - dir] = SAND;
                            grid[y][x] = EMPTY;
                        }
                    }
                } else {
                    // Blocked by another sand or wall, try diagonal
                    const dir = Math.random() > 0.5 ? -1 : 1;
                    const side1 = x + dir >= 0 && x + dir < this.w ? grid[y + 1][x + dir] : WALL;

                    if (side1 === EMPTY) {
                        grid[y + 1][x + dir] = SAND;
                        grid[y][x] = EMPTY;
                    } else {
                        const side2 = x - dir >= 0 && x - dir < this.w ? grid[y + 1][x - dir] : WALL;
                        if (side2 === EMPTY) {
                            grid[y + 1][x - dir] = SAND;
                            grid[y][x] = EMPTY;
                        }
                    }
                }
            }

            updateWater(x, y, grid) {
                if (y >= this.h - 1) return; // Bottom boundary

                const below = grid[y + 1][x];

                // Try to fall straight down
                if (below === EMPTY) {
                    grid[y + 1][x] = WATER;
                    grid[y][x] = EMPTY;
                } else {
                    // Try horizontal spreading
                    const dir = Math.random() > 0.5 ? -1 : 1;
                    const side1 = x + dir >= 0 && x + dir < this.w ? grid[y][x + dir] : WALL;

                    if (side1 === EMPTY) {
                        grid[y][x + dir] = WATER;
                        grid[y][x] = EMPTY;
                    } else {
                        const side2 = x - dir >= 0 && x - dir < this.w ? grid[y][x - dir] : WALL;
                        if (side2 === EMPTY) {
                            grid[y][x - dir] = WATER;
                            grid[y][x] = EMPTY;
                        }
                    }
                }
            }

            updateAcid(x, y, grid) {
                if (y >= this.h - 1) return; // Bottom boundary

                const below = grid[y + 1][x];

                // Try to fall straight down
                if (below === EMPTY) {
                    grid[y + 1][x] = ACID;
                    grid[y][x] = EMPTY;
                } else if (below === SAND || below === WALL) {
                    // Acid dissolves sand and walls
                    if (Math.random() > 0.3) { // Not all acid reactions happen instantly
                        grid[y + 1][x] = EMPTY; // Dissolved material becomes empty
                        grid[y][x] = Math.random() > 0.5 ? EMPTY : ACID; // Acid may be consumed
                    }
                } else {
                    // Try horizontal spreading
                    const dir = Math.random() > 0.5 ? -1 : 1;
                    const side1 = x + dir >= 0 && x + dir < this.w ? grid[y][x + dir] : WALL;

                    if (side1 === EMPTY) {
                        grid[y][x + dir] = ACID;
                        grid[y][x] = EMPTY;
                    } else if (side1 === SAND || side1 === WALL) {
                        // Acid dissolves sand and walls
                        if (Math.random() > 0.3) {
                            grid[y][x + dir] = EMPTY; // Dissolved material becomes empty
                            grid[y][x] = Math.random() > 0.5 ? EMPTY : ACID; // Acid may be consumed
                        }
                    } else {
                        const side2 = x - dir >= 0 && x - dir < this.w ? grid[y][x - dir] : WALL;
                        if (side2 === EMPTY) {
                            grid[y][x - dir] = ACID;
                            grid[y][x] = EMPTY;
                        } else if (side2 === SAND || side2 === WALL) {
                            // Acid dissolves sand and walls
                            if (Math.random() > 0.3) {
                                grid[y][x - dir] = EMPTY; // Dissolved material becomes empty
                                grid[y][x] = Math.random() > 0.5 ? EMPTY : ACID; // Acid may be consumed
                            }
                        }
                    }
                }
            }

            render() {
                this.ctx.fillStyle = '#121212';
                this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

                for (let y = 0; y < this.h; y++) {
                    for (let x = 0; x < this.w; x++) {
                        const material = this.grid[y][x];

                        if (material === EMPTY) continue;

                        let color;
                        switch (material) {
                            case SAND:
                                // Gradient of sand colors
                                const sandShade = Math.floor(Math.random() * 3);
                                if (sandShade === 0) color = '#e6c288'; // Light sand
                                else if (sandShade === 1) color = '#d4b075'; // Medium sand
                                else color = '#c29e62'; // Dark sand
                                break;
                            case WATER:
                                // Gradient of water colors
                                const waterShade = Math.floor(Math.random() * 3);
                                if (waterShade === 0) color = '#4fc3f7'; // Light blue
                                else if (waterShade === 1) color = '#29b6f6'; // Medium blue
                                else color = '#03a9f4'; // Darker blue
                                break;
                            case WALL:
                                // Concrete-like colors
                                const wallShade = Math.floor(Math.random() * 3);
                                if (wallShade === 0) color = '#757575'; // Light gray
                                else if (wallShade === 1) color = '#616161'; // Medium gray
                                else color = '#424242'; // Dark gray
                                break;
                            case ACID:
                                // Acid colors - green/yellow
                                const acidShade = Math.floor(Math.random() * 3);
                                if (acidShade === 0) color = '#cddc39'; // Lime
                                else if (acidShade === 1) color = '#8bc34a'; // Light green
                                else color = '#7cb342'; // Darker green
                                break;
                        }

                        this.ctx.fillStyle = color;
                        this.ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
                    }
                }
            }
        }

        // Initialize simulation
        const sim = new FallingSandSimulation(GRID_WIDTH, GRID_HEIGHT);

        // Expose to window as required
        window.sim = {
            w: sim.w,
            h: sim.h,
            tick: (n) => sim.tick(n),
            get: (x, y) => sim.get(x, y),
            set: (x, y, material) => sim.set(x, y, material),
            clear: () => sim.clear()
        };

        // Material buttons
        const matButtons = {
            sand: document.getElementById('mat-sand'),
            water: document.getElementById('mat-water'),
            wall: document.getElementById('mat-wall'),
            acid: document.getElementById('mat-acid'),
            empty: document.getElementById('mat-empty')
        };

        function setActiveMaterial(material) {
            // Update UI
            Object.values(matButtons).forEach(btn => btn.classList.remove('active'));

            switch (material) {
                case SAND:
                    matButtons.sand.classList.add('active');
                    break;
                case WATER:
                    matButtons.water.classList.add('active');
                    break;
                case WALL:
                    matButtons.wall.classList.add('active');
                    break;
                case ACID:
                    matButtons.acid.classList.add('active');
                    break;
                case EMPTY:
                    matButtons.empty.classList.add('active');
                    break;
            }

            sim.currentMaterial = material;
        }

        // Bind button events
        matButtons.sand.addEventListener('click', () => setActiveMaterial(SAND));
        matButtons.water.addEventListener('click', () => setActiveMaterial(WATER));
        matButtons.wall.addEventListener('click', () => setActiveMaterial(WALL));
        matButtons.acid.addEventListener('click', () => setActiveMaterial(ACID));
        matButtons.empty.addEventListener('click', () => setActiveMaterial(EMPTY));

        // Clear button
        document.getElementById('clear').addEventListener('click', () => {
            sim.clear();
        });

        // Start animation loop
        function animate() {
            // Run a few simulation steps per frame for satisfying motion
            sim.tick(2);
            requestAnimationFrame(animate);
        }

        // Initialize with some random sand for demo
        for (let i = 0; i < 50; i++) {
            const x = Math.floor(Math.random() * GRID_WIDTH);
            const y = Math.floor(Math.random() * (GRID_HEIGHT / 4));
            sim.set(x, y, SAND);
        }

        // Start animation
        animate();
    </script>
</body>
</html>
